"use client";
import { DrawerSlide } from "@/components/ui/drawer-slide";
import { useState } from "react";

export default function NavDrawer() {
  const [open, setOpen] = useState(false);

  return (
    <div className="flex items-center justify-center p-20">
      <button
        onClick={() => setOpen(true)}
        className="px-4 py-2 bg-neutral-800 text-white rounded-lg text-sm"
      >
        Open menu
      </button>
      <DrawerSlide isOpen={open} onClose={() => setOpen(false)} position="left" width="280px" ariaLabel="Navigation menu">
        <nav className="space-y-2">
          {["Home", "Components", "Docs", "GitHub"].map((item) => (
            <a key={item} href="#" className="block px-3 py-2 rounded-lg text-neutral-300 hover:bg-neutral-800 text-sm">
              {item}
            </a>
          ))}
        </nav>
      </DrawerSlide>
    </div>
  );
}

"use client";
import { DrawerSlide } from "@/components/ui/drawer-slide";
import { useState } from "react";

export default function ActionSheet() {
  const [open, setOpen] = useState(false);

  return (
    <div className="flex items-center justify-center p-20">
      <button
        onClick={() => setOpen(true)}
        className="px-4 py-2 bg-neutral-800 text-white rounded-lg text-sm"
      >
        Share
      </button>
      <DrawerSlide isOpen={open} onClose={() => setOpen(false)} position="bottom" height="220px" ariaLabel="Share options">
        <div className="space-y-3">
          <h3 className="text-white font-semibold">Share this page</h3>
          {["Copy link", "Share to Twitter", "Share to LinkedIn"].map((action) => (
            <button key={action} onClick={() => setOpen(false)} className="w-full text-left px-4 py-3 rounded-lg bg-neutral-800/50 text-neutral-300 text-sm">
              {action}
            </button>
          ))}
        </div>
      </DrawerSlide>
    </div>
  );
}
